-- Clean existing bookings + notifications in range to avoid conflicts
DELETE FROM notifications WHERE org_id = 'd0000000-0000-0000-0000-000000000001'
  AND booking_id IN (
    SELECT id FROM bookings WHERE org_id = 'd0000000-0000-0000-0000-000000000001'
      AND start_time >= '2026-07-01T00:00:00-06:00'
      AND start_time <  '2026-07-06T00:00:00-06:00'
  );
DELETE FROM bookings WHERE org_id = 'd0000000-0000-0000-0000-000000000001'
  AND start_time >= '2026-07-01T00:00:00-06:00'
  AND start_time <  '2026-07-06T00:00:00-06:00';

